document.addEventListener("DOMContentLoaded",()=>{console.log("Website Yh'rez Grafika Berhasil Dimuat.");document.querySelectorAll('a[href^="#"]').forEach((anchor)=>{anchor.addEventListener("click",function (e){e.preventDefault();const target =document.querySelector(this.getAttribute("href"));if (target){window.scrollTo({top:target.offsetTop -80,behavior:"smooth",});}});});const nav =document.getElementById("main-nav");const waFloat =document.querySelector(".wa-float");const WA_SHOW_DELAY =1200;const WA_HIDE_IDLE_DELAY =2200;let waShowTimer =null;let waHideTimer =null;let navCompact =false;const onScroll =()=>{const y =window.scrollY;const shouldCompact =y >100;if (shouldCompact !==navCompact){navCompact =shouldCompact;if (navCompact){nav.classList.add("navbar-scrolled");}else {nav.classList.remove("navbar-scrolled");}}if (!waFloat)return;if (shouldCompact){if (!waFloat.classList.contains("show")&&!waShowTimer){waShowTimer =setTimeout(()=>{waFloat.classList.add("show");waShowTimer =null;},WA_SHOW_DELAY);}if (waHideTimer)clearTimeout(waHideTimer);waHideTimer =setTimeout(()=>{waFloat.classList.remove("show");},WA_HIDE_IDLE_DELAY);}else {if (waShowTimer){clearTimeout(waShowTimer);waShowTimer =null;}if (waHideTimer){clearTimeout(waHideTimer);waHideTimer =null;}waFloat.classList.remove("show");}};window.addEventListener("scroll",onScroll,{passive:true });onScroll();const menuToggle =document.getElementById("mobile-menu");const navLinks =document.querySelector(".nav-links");if (menuToggle &&navLinks){menuToggle.addEventListener("click",function (){navLinks.classList.toggle("active");const icon =menuToggle.querySelector("i");if (icon){icon.classList.toggle("fa-bars");icon.classList.toggle("fa-times");}});document.querySelectorAll(".nav-links a").forEach((link)=>{link.addEventListener("click",()=>{navLinks.classList.remove("active");const icon =menuToggle.querySelector("i");if (icon){icon.classList.add("fa-bars");icon.classList.remove("fa-times");}});});}const revealElements =document.querySelectorAll(".product-card, .testimonial-card, .portfolio-item");if (window.matchMedia("(max-width: 768px)").matches ||!("IntersectionObserver"in window)){revealElements.forEach((el)=>{el.style.opacity ="1";el.style.transform ="none";el.style.transition ="none";});}else {const revealObserver =new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if (entry.isIntersecting){entry.target.classList.add("active","show");entry.target.style.opacity ="1";entry.target.style.transform ="translateY(0)";revealObserver.unobserve(entry.target);}});},{threshold:0.15 },);revealElements.forEach((el)=>{el.style.opacity ="0";el.style.transform ="translateY(30px)";el.style.transition ="opacity 0.5s ease-out, transform 0.5s ease-out";revealObserver.observe(el);});}const filterContainer =document.querySelector(".filter-buttons");const productCards =document.querySelectorAll(".product-card");if (productCards.length &&filterContainer){filterContainer.addEventListener("click",(event)=>{const btn =event.target.closest(".filter-btn");if (!btn)return;filterContainer.querySelectorAll(".filter-btn").forEach((b)=>b.classList.remove("active"));btn.classList.add("active");const filter =btn.getAttribute("data-filter")||"all";productCards.forEach((card)=>{const category =card.getAttribute("data-category");const shouldShow =filter ==="all"||category ===filter;card.style.display =shouldShow ?"block":"none";});});}const waButtons =document.querySelectorAll(".btn-wa");const phoneNumber ="6281348520154";waButtons.forEach((btn)=>{btn.addEventListener("click",(event)=>{event.preventDefault();const card =btn.closest(".product-card");const productName =btn.getAttribute("data-product")||card?.querySelector("h3")?.textContent?.trim();const customMessage =btn.getAttribute("data-message");const message =customMessage ||(productName ?`Halo, saya ingin pesan ${productName} di Yh'rez Grafika.`:"");if (message){window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`,"_blank");}});});const slides =document.querySelectorAll(".about-slide");if (slides.length >1){let currentSlide =0;setInterval(()=>{slides[currentSlide].classList.remove("active");currentSlide =(currentSlide +1)%slides.length;slides[currentSlide].classList.add("active");},3000);}const modal =document.getElementById("imageModal");const modalImg =document.getElementById("modalImage");const closeBtn =document.querySelector(".close-modal");const images =document.querySelectorAll(".print-portfolio-card img, .portfolio-item img");if (modal &&modalImg){images.forEach((img)=>{img.addEventListener("click",()=>{modal.style.display ="block";modalImg.src =img.src;});});if (closeBtn){closeBtn.addEventListener("click",()=>(modal.style.display ="none"));}modal.addEventListener("click",(e)=>{if (e.target ===modal)modal.style.display ="none";});}const hariEl =document.getElementById("tanggal-hari");if (hariEl){const formattedDate =new Intl.DateTimeFormat("id-ID",{weekday:"long",day:"numeric",month:"long",year:"numeric",}).format(new Date());requestAnimationFrame(()=>{hariEl.textContent =formattedDate;});}});